## 1) Worker configs by queue

```ts
import { Worker } from 'bullmq';
import IORedis from 'ioredis';

const connection = new IORedis(process.env.REDIS_URL!, {
  maxRetriesPerRequest: null,
  enableReadyCheck: false,
});
const prefix = 'acme:prod:bull';

const criticalWorker = new Worker(
  'jobs:critical',
  async (job) => processCritical(job),
  {
    connection,
    prefix,
    concurrency: 2,
    limiter: {
      // Optional global worker-side throttle for critical external dependencies
      max: 20,
      duration: 1000, // max 20 jobs/sec across this worker instance
    },
    settings: {
      stalledInterval: 30_000,
      maxStalledCount: 1,
    },
  }
);

const standardWorker = new Worker(
  'jobs:standard',
  async (job) => processStandard(job),
  {
    connection,
    prefix,
    concurrency: 10,
    limiter: {
      max: 100,
      duration: 1000,
    },
    settings: {
      stalledInterval: 30_000,
      maxStalledCount: 1,
    },
  }
);

const bulkWorker = new Worker(
  'jobs:bulk',
  async (job) => processBulk(job),
  {
    connection,
    prefix,
    concurrency: 50,
    limiter: {
      // Critical guardrail: cap pull rate regardless of queue depth
      max: 200,
      duration: 1000,
    },
    settings: {
      stalledInterval: 60_000,
      maxStalledCount: 1,
    },
  }
);
```

Note: tune limiter numbers empirically. Start conservative.

