## 2) Instrumentation approach

You need two collectors:

1. **Event-driven collector** (`QueueEvents`) for lifecycle counters/histograms.
2. **Polling collector** (every 10–30s) for queue depth gauges via `queue.getJobCounts()` and oldest waiting age.

### Example: metrics registry

```ts
import client from 'prom-client';

export const register = new client.Registry();
client.collectDefaultMetrics({ register });

export const jobsCompleted = new client.Counter({
  name: 'bullmq_jobs_completed_total',
  help: 'Total completed jobs',
  labelNames: ['queue', 'job_name'],
  registers: [register],
});

export const jobsFailed = new client.Counter({
  name: 'bullmq_jobs_failed_total',
  help: 'Total failed jobs',
  labelNames: ['queue', 'job_name', 'error_class'],
  registers: [register],
});

export const jobsRetried = new client.Counter({
  name: 'bullmq_jobs_retried_total',
  help: 'Total retry attempts',
  labelNames: ['queue', 'job_name'],
  registers: [register],
});

export const processingHist = new client.Histogram({
  name: 'bullmq_job_processing_seconds',
  help: 'Job processing duration',
  labelNames: ['queue', 'job_name'],
  buckets: [0.1, 0.5, 1, 2, 5, 10, 30, 60, 120, 300, 900],
  registers: [register],
});

export const e2eHist = new client.Histogram({
  name: 'bullmq_job_end_to_end_seconds',
  help: 'Job end-to-end duration',
  labelNames: ['queue', 'job_name'],
  buckets: [0.5, 1, 2, 5, 10, 30, 60, 120, 300, 900, 1800, 3600],
  registers: [register],
});

export const queueWaiting = new client.Gauge({
  name: 'bullmq_queue_waiting',
  help: 'Waiting jobs per queue',
  labelNames: ['queue'],
  registers: [register],
});
