### Event consumer hooks

```ts
import { QueueEvents, Queue } from 'bullmq';

const queues = ['jobs:critical', 'jobs:standard', 'jobs:bulk'] as const;
const activeStart = new Map<string, number>(); // key: queue:jobId

function key(queue: string, jobId: string) { return `${queue}:${jobId}`; }

for (const qName of queues) {
  const ev = new QueueEvents(qName, { connection, prefix });
  const q = new Queue(qName, { connection, prefix });

  ev.on('active', ({ jobId }) => {
    activeStart.set(key(qName, jobId), Date.now());
  });

  ev.on('completed', async ({ jobId }) => {
    const job = await q.getJob(jobId);
    if (!job) return;

    jobsCompleted.inc({ queue: qName, job_name: job.name }, 1);

    const start = activeStart.get(key(qName, jobId));
    if (start) {
      processingHist.observe({ queue: qName, job_name: job.name }, (Date.now() - start) / 1000);
      activeStart.delete(key(qName, jobId));
    }

    const ts = job.timestamp; // enqueue time in ms
    e2eHist.observe({ queue: qName, job_name: job.name }, (Date.now() - ts) / 1000);
  });

  ev.on('failed', async ({ jobId, failedReason }) => {
    const job = await q.getJob(jobId);
    if (!job) return;

    const errorClass = failedReason?.includes('UnrecoverableError') ? 'non_retryable' : 'retryable_or_exhausted';
    jobsFailed.inc({ queue: qName, job_name: job.name, error_class: errorClass }, 1);

    if ((job.attemptsMade ?? 0) > 1) {
      jobsRetried.inc({ queue: qName, job_name: job.name }, 1);
    }

    const start = activeStart.get(key(qName, jobId));
    if (start) {
      processingHist.observe({ queue: qName, job_name: job.name }, (Date.now() - start) / 1000);
      activeStart.delete(key(qName, jobId));
    }
  });
}
```

